export default function AccountLayout({children}:{children:ReactNode}){const {session}=useAuth(),path=usePathname()||"";if(!session)return <PrewiseShell><main className="account-locked"><span>◎</span><h1>Khu vực tài khoản được bảo vệ</h1><p>Đăng nhập để quản lý hồ sơ, gói dịch vụ và khóa tích hợp.</p><Link href="/">Về trang chủ →</Link></main></PrewiseShell>;return <PrewiseShell><main className="account-shell"><aside><span>ACCOUNT / CONTROL</span><nav>{nav.map(x=>{const active=x.exact?path===x.href:path===x.href||path.startsWith(x.href+"/");return <Link className={active?"active":""} href={x.href} key={x.href}>{x.label}<i>→</i></Link>})}</nav><small>SESSION · ENCRYPTED</small></aside><section className="account-content">{children}</section></main></PrewiseShell>}
